import { RouteRecordRaw } from 'vue-router';

// check if user is logged in
// if not, redirect to login page



const routes: RouteRecordRaw[] = [

  {
    path: '/admin',
    component: () => import('../layouts/AdminLayout.vue'),
    meta: { requiresAuth: false },
    name: 'admin',
    children: [
      { path: '/admin/dashboard', name: 'admin-dashboard', component: () => import('../pages/DashboardPage.vue') },
      { path: '/admin/:model', name: 'admin-dt', component: () => import('../pages/DataTablePage.vue') }
    ],
  },
  {
    path: '/action',
    component: () => import('../layouts/AdminLayout.vue'),
    meta: { requiresAuth: false },
    name: 'action',
    children: [
      { path: '/action/:type', name: 'action-t', component: () => import('../pages/ActionPage.vue') }
    ],
  }
];

export default routes;
